#include <stdio.h>
#include <math.h>

typedef struct { float t,hx,hy,hz,nx,ny,nz; int hit; } Hit;

/* sphere center (0,-0.5,-5) radius 1 */
static Hit isect(float ox,float oy,float oz,float dx,float dy,float dz){
    Hit h; h.hit=0;
    float cx=0.0f,cy=-0.5f,cz=-5.0f,r=1.0f;
    float ocx=ox-cx,ocy=oy-cy,ocz=oz-cz;
    float a=dx*dx+dy*dy+dz*dz;
    float b=2.0f*(ocx*dx+ocy*dy+ocz*dz);
    float c=ocx*ocx+ocy*ocy+ocz*ocz-r*r;
    float disc=b*b-4.0f*a*c;
    if(disc<0.0f) return h;
    double sq=sqrt((double)disc);
    double a2=(double)(a+a);
    float t=(float)(((double)(-b)-sq)/a2);
    if(!(0.001f<=t)){
        t=(float)(((double)(-b)+sq)/a2);
        if(!(0.001f<=t)) return h;
    }
    float hx=dx*t+ox,hy=dy*t+oy,hz=dz*t+oz;
    float nx=hx-cx,ny=hy-cy,nz=hz-cz;
    float nl=sqrtf(nx*nx+ny*ny+nz*nz);
    h.t=t;h.hx=hx;h.hy=hy;h.hz=hz;h.nx=nx/nl;h.ny=ny/nl;h.nz=nz/nl;h.hit=1;
    return h;
}

int main(void){
    int W=800,H=600;
    fprintf(stderr,"Creating high-resolution image: %dx%d\n",W,H);
    fputs("This will be downsampled with ffmpeg after rendering\n",stderr);
    /* normalized light */
    float lx0=1.0f,ly0=1.0f,lz0=-1.0f;
    float ll=sqrtf(lx0*lx0+ly0*ly0+lz0*lz0);
    float Lx=lx0/ll,Ly=ly0/ll,Lz=lz0/ll;
    float *img=(float*)malloc((size_t)W*H*3*sizeof(float));
    fputs("Rendering high-resolution image...\n",stderr);
    float aspect=4.0f/3.0f;
    for(int y=0;y<H;y++){
        fprintf(stderr,"\rProgress: %.1f%%",(double)(100.0f*(float)y/600.0f));
        for(int x=0;x<W;x++){
            float u=((float)x/799.0f)*(2.0f*aspect)-aspect;
            float v=2.0f*(1.0f-(float)y/599.0f)-1.0f;
            float z0=-1.0f;
            float dl=sqrtf(u*u+v*v+z0*z0);
            float dx=u/dl,dy=v/dl,dz=z0/dl;
            Hit s=isect(0.0f,0.0f,0.0f,dx,dy,dz);
            int r13=s.hit;
            float r,g,b;
            int mode; /* 0 sphere,1 floor,2 sky */
            float tp=0.0f;
            if(fabsf(dy)<1e-4f){
                mode=r13?0:2;
            }else{
                tp=-1.5f/dy;
                if(0.001f>tp){
                    mode=r13?0:2;
                }else{
                    if(r13&&(tp>s.t)) mode=0; else mode=1;
                }
            }
            if(mode==2){
                float t=0.5f*(dy+1.0f);
                float omt=1.0f-t;
                r=t*0.5f+omt; g=t*0.7f+omt; b=t+omt;
            }else{
                float hx,hy,hz,nx,ny,nz;
                if(mode==0){ hx=s.hx;hy=s.hy;hz=s.hz;nx=s.nx;ny=s.ny;nz=s.nz; }
                else{ hx=dx*tp;hz=dz*tp;hy=dy*tp;nx=0.0f;ny=1.0f;nz=0.0f; }
                float ox=hx+nx*0.001f,oy=hy+ny*0.001f,oz=hz+nz*0.001f;
                float ml=sqrtf(Lx*Lx+Ly*Ly+Lz*Lz);
                Hit sh=isect(ox,oy,oz,Lx/ml,Ly/ml,Lz/ml);
                float intensity;
                if(sh.hit) intensity=0.2f;
                else{
                    float dot=(nx*Lx+ny*Ly)+nz*Lz;
                    double md=fmax((double)dot,0.0);
                    intensity=0.2f+0.8f*(float)md;
                }
                if(mode==0){ r=intensity; g=0.2f*intensity; b=0.2f*intensity; }
                else{
                    long p=(long)((double)floorf(hx)+(double)floorf(hz));
                    float checker=(p&1)?0.4f:0.9f;
                    float cc=checker*intensity;
                    r=cc;g=cc;b=cc;
                }
            }
            float *px=img+((size_t)y*W+x)*3;
            px[0]=r;px[1]=g;px[2]=b;
        }
    }
    fputs("\nRendering complete\n",stderr);
    FILE *fp=fopen("image.ppm","w");
    fprintf(fp,"P3\n%d %d\n255\n",W,H);
    for(int y=0;y<H;y++)for(int x=0;x<W;x++){
        float *px=img+((size_t)y*W+x)*3;
        int o[3];
        for(int k=0;k<3;k++){
            double d=(double)px[k]; d=fmax(d,0.0); d=fmin(d,1.0);
            float f=(float)d*255.99f; o[k]=(int)f;
        }
        fprintf(fp,"%d %d %d\n",o[0],o[1],o[2]);
    }
    fclose(fp);
    fprintf(stderr,"Wrote image to %s\n","image.ppm");
    free(img);
    fputs("Done.\n",stderr);
    return 0;
}

